    private JavaVersion createVersion(int num, String name, String date, boolean lts,
                                       String codename, String desc,
                                       List<String> features, List<CodeExample> examples) {
        JavaVersion v = new JavaVersion();
        v.setVersionNumber(num);
        v.setReleaseName(name);
        v.setReleaseDate(date);
        v.setLts(lts);
        v.setCodename(codename);
        v.setDescription(desc);
        v.setKeyFeatures(features);
        v.setCodeExamples(examples);
        return v;
    }

    private void seedTopics() {
        List<Topic> topics = List.of(
            createTopic("Object-Oriented Programming", "oop", "Core Java", "Beginner",
                "Master the four pillars of OOP in Java: Encapsulation, Inheritance, Polymorphism, and Abstraction.",
                "## Object-Oriented Programming in Java\n\nJava is a class-based, object-oriented programming language. Everything in Java is associated with classes and objects.\n\n### The Four Pillars\n\n1. **Encapsulation** - Bundling data and methods that operate on that data within a single unit (class), restricting direct access to some components.\n\n2. **Inheritance** - A mechanism where a new class inherits properties and behaviors from an existing class.\n\n3. **Polymorphism** - The ability of an object to take on many forms. Method overloading (compile-time) and method overriding (runtime).\n\n4. **Abstraction** - Hiding complex implementation details and showing only the necessary features of an object.",
                List.of(
                    new CodeExample("Four Pillars of OOP", "java",
                        "// ENCAPSULATION\nclass BankAccount {\n    private double balance; // hidden field\n\n    public void deposit(double amount) {\n        if (amount > 0) balance += amount;\n    }\n\n    public double getBalance() { return balance; }\n}\n\n// INHERITANCE\nclass Animal {\n    void speak() { System.out.println(\"...\"); }\n}\nclass Dog extends Animal {\n    @Override\n    void speak() { System.out.println(\"Woof!\"); } // POLYMORPHISM\n}\nclass Cat extends Animal {\n    @Override\n    void speak() { System.out.println(\"Meow!\"); }\n}\n\n// ABSTRACTION\nabstract class Shape {\n    abstract double area(); // abstract method\n    void display() { System.out.println(\"Area: \" + area()); }\n}\nclass Circle extends Shape {\n    private double radius;\n    Circle(double r) { this.radius = r; }\n    @Override\n    double area() { return Math.PI * radius * radius; }\n}",
                        "This example demonstrates all four OOP pillars in practice."),
                    new CodeExample("Interfaces & Abstract Classes", "java",
                        "// Interface - contract for behavior\ninterface Flyable {\n    void fly();\n    default void land() {\n        System.out.println(\"Landing safely...\");\n    }\n}\n\ninterface Swimmable {\n    void swim();\n}\n\n// Multiple interface implementation\nclass Duck extends Animal implements Flyable, Swimmable {\n    @Override\n    void speak() { System.out.println(\"Quack!\"); }\n\n    @Override\n    public void fly() { System.out.println(\"Flying!\"); }\n\n    @Override\n    public void swim() { System.out.println(\"Swimming!\"); }\n}",
                        "Interfaces define contracts, and a class can implement multiple interfaces — Java's way of achieving multiple inheritance of behavior.")),
                List.of("What are the four pillars of OOP?", "Difference between abstract class and interface?", "What is method overloading vs overriding?", "Explain IS-A and HAS-A relationships.", "What is the diamond problem? How does Java solve it?"),
                List.of("oop", "encapsulation", "inheritance", "polymorphism", "abstraction", "classes", "objects")),

            createTopic("Collections Framework", "collections", "Core Java", "Intermediate",
                "Deep dive into Java Collections: List, Set, Map, Queue — understand when to use which implementation.",
                "## Java Collections Framework\n\nThe Collections Framework provides a unified architecture for storing and manipulating groups of objects.\n\n### Hierarchy\n- **Collection** (interface)\n  - **List** - Ordered, allows duplicates (ArrayList, LinkedList, Vector)\n  - **Set** - No duplicates (HashSet, TreeSet, LinkedHashSet)\n  - **Queue** - FIFO ordering (PriorityQueue, ArrayDeque)\n- **Map** (interface) - Key-value pairs (HashMap, TreeMap, LinkedHashMap, ConcurrentHashMap)",
                List.of(
                    new CodeExample("List, Set, Map Comparison", "java",
                        "import java.util.*;\n\npublic class CollectionsDeepDive {\n    public static void main(String[] args) {\n        // ArrayList - fast random access, slow insert/delete in middle\n        List<String> arrayList = new ArrayList<>(List.of(\"B\",\"A\",\"C\",\"A\"));\n        System.out.println(\"ArrayList: \" + arrayList); // [B, A, C, A]\n\n        // LinkedList - fast insert/delete, slow random access\n        List<String> linkedList = new LinkedList<>(arrayList);\n        linkedList.addFirst(\"Z\");\n\n        // HashSet - no duplicates, unordered, O(1) operations\n        Set<String> hashSet = new HashSet<>(arrayList);\n        System.out.println(\"HashSet: \" + hashSet); // No duplicates\n\n        // TreeSet - sorted, O(log n) operations\n        Set<String> treeSet = new TreeSet<>(arrayList);\n        System.out.println(\"TreeSet: \" + treeSet); // [A, B, C]\n\n        // HashMap - key-value, unordered\n        Map<String, Integer> map = new HashMap<>();\n        map.put(\"Java\", 1995);\n        map.put(\"Python\", 1991);\n        map.computeIfAbsent(\"Kotlin\", k -> 2011);\n\n        // ConcurrentHashMap - thread-safe\n        Map<String, Integer> concurrent = new java.util.concurrent.ConcurrentHashMap<>(map);\n    }\n}",
                        "Understanding the performance characteristics of each collection type is critical for choosing the right data structure.")),
                List.of("ArrayList vs LinkedList — when to use which?", "How does HashMap work internally?", "Difference between HashMap and ConcurrentHashMap?", "What is the difference between Comparable and Comparator?", "How does TreeMap maintain sorted order?", "What is fail-fast vs fail-safe iterator?"),
                List.of("collections", "list", "set", "map", "arraylist", "hashmap", "treemap")),

            createTopic("Lambda Expressions & Functional Programming", "lambdas", "Java 8+", "Intermediate",
                "Understand lambda expressions, functional interfaces, method references, and how Java embraces functional programming.",
                "## Functional Programming in Java\n\nJava 8 introduced functional programming concepts with lambda expressions, functional interfaces, and the Stream API.\n\n### Key Concepts\n- **Lambda Expression** - Anonymous function: `(params) -> expression`\n- **Functional Interface** - Interface with exactly one abstract method\n- **Method Reference** - Shorthand for lambdas: `ClassName::methodName`\n- **Built-in Functional Interfaces** - Predicate, Function, Consumer, Supplier, etc.",
                List.of(new CodeExample("Lambdas & Functional Interfaces", "java",
                    "import java.util.function.*;\nimport java.util.*;\n\npublic class FunctionalJava {\n    public static void main(String[] args) {\n        // Predicate - takes T, returns boolean\n        Predicate<String> isLong = s -> s.length() > 5;\n        System.out.println(isLong.test(\"Hello\")); // false\n        System.out.println(isLong.test(\"Hello World\")); // true\n\n        // Function - takes T, returns R\n        Function<String, Integer> length = String::length;\n        System.out.println(length.apply(\"Java\")); // 4\n\n        // Consumer - takes T, returns void\n        Consumer<String> printer = System.out::println;\n        printer.accept(\"Hello!\");\n\n        // Supplier - takes nothing, returns T\n        Supplier<List<String>> listFactory = ArrayList::new;\n        List<String> newList = listFactory.get();\n\n        // BiFunction - takes T, U, returns R\n        BiFunction<Integer, Integer, Integer> add = Integer::sum;\n        System.out.println(add.apply(3, 4)); // 7\n\n        // Chaining\n        Function<Integer, Integer> doubleIt = x -> x * 2;\n        Function<Integer, Integer> addTen = x -> x + 10;\n        Function<Integer, Integer> doubleThenAdd = doubleIt.andThen(addTen);\n        System.out.println(doubleThenAdd.apply(5)); // 20\n    }\n}",
                    "Java provides built-in functional interfaces in java.util.function — Predicate, Function, Consumer, Supplier — that cover most common use cases.")),
                List.of("What is a functional interface?", "Can a lambda expression access local variables?", "What is the difference between Predicate and Function?", "Explain method references with examples.", "What are effectively final variables?"),
                List.of("lambda", "functional", "predicate", "function", "consumer", "supplier", "method-reference")),

            createTopic("Stream API", "streams", "Java 8+", "Intermediate",
                "Master the Stream API for declarative data processing — filter, map, reduce, collect, and parallel streams.",
                "## Java Stream API\n\nStreams provide a declarative way to process collections of data. They support sequential and parallel operations.\n\n### Stream Pipeline\n1. **Source** - Collection, array, generator, I/O channel\n2. **Intermediate Operations** - filter, map, flatMap, sorted, distinct, peek (lazy)\n3. **Terminal Operations** - collect, forEach, reduce, count, findFirst, anyMatch (trigger execution)",
                List.of(new CodeExample("Stream Operations Deep Dive", "java",
                    "import java.util.*;\nimport java.util.stream.*;\n\nrecord Employee(String name, String dept, double salary) {}\n\npublic class StreamMastery {\n    public static void main(String[] args) {\n        var employees = List.of(\n            new Employee(\"Alice\", \"Engineering\", 95000),\n            new Employee(\"Bob\", \"Marketing\", 75000),\n            new Employee(\"Charlie\", \"Engineering\", 105000),\n            new Employee(\"Diana\", \"HR\", 82000),\n            new Employee(\"Eve\", \"Engineering\", 92000),\n            new Employee(\"Frank\", \"Marketing\", 68000)\n        );\n\n        // Group by department\n        Map<String, List<Employee>> byDept = employees.stream()\n            .collect(Collectors.groupingBy(Employee::dept));\n\n        // Average salary per department\n        Map<String, Double> avgSalary = employees.stream()\n            .collect(Collectors.groupingBy(\n                Employee::dept,\n                Collectors.averagingDouble(Employee::salary)));\n        System.out.println(\"Avg salaries: \" + avgSalary);\n\n        // Top 3 earners\n        var topEarners = employees.stream()\n            .sorted(Comparator.comparingDouble(Employee::salary).reversed())\n            .limit(3)\n            .map(Employee::name)\n            .collect(Collectors.joining(\", \"));\n        System.out.println(\"Top 3: \" + topEarners);\n\n        // Partition by salary threshold\n        Map<Boolean, List<Employee>> partition = employees.stream()\n            .collect(Collectors.partitioningBy(\n                e -> e.salary() > 80000));\n        System.out.println(\"Above 80K: \" +\n            partition.get(true).size());\n    }\n}",
                    "Streams enable powerful data transformations with grouping, partitioning, and complex aggregations — all in a readable, declarative style.")),
                List.of("What is the difference between intermediate and terminal operations?", "How do parallel streams work?", "What is the difference between map() and flatMap()?", "Explain Collectors.groupingBy() with examples.", "When should you NOT use streams?"),
                List.of("streams", "filter", "map", "reduce", "collect", "parallel-streams")),

            createTopic("Concurrency & Multithreading", "concurrency", "Advanced", "Advanced",
                "Master Java concurrency: threads, synchronization, executors, locks, concurrent collections, and virtual threads.",
                "## Java Concurrency\n\nJava has rich support for concurrent programming, evolving from basic Thread/Runnable to the modern virtual threads.\n\n### Evolution of Concurrency in Java\n1. **Java 1.0** - Thread, Runnable, synchronized\n2. **Java 5** - java.util.concurrent (Executor, locks, atomic, concurrent collections)\n3. **Java 7** - Fork/Join framework\n4. **Java 8** - CompletableFuture, parallel streams\n5. **Java 21** - Virtual Threads (Project Loom)",
                List.of(new CodeExample("Concurrency Essentials", "java",
                    "import java.util.concurrent.*;\nimport java.util.concurrent.atomic.*;\nimport java.util.concurrent.locks.*;\n\npublic class ConcurrencyMastery {\n    // AtomicInteger for thread-safe counting\n    private static final AtomicInteger counter = new AtomicInteger(0);\n\n    // ReentrantLock for fine-grained locking\n    private static final ReentrantLock lock = new ReentrantLock();\n\n    public static void main(String[] args) throws Exception {\n        // ExecutorService with thread pool\n        ExecutorService executor = Executors.newFixedThreadPool(4);\n\n        // Submit tasks\n        List<Future<Integer>> futures = new java.util.ArrayList<>();\n        for (int i = 0; i < 10; i++) {\n            futures.add(executor.submit(() -> {\n                counter.incrementAndGet();\n                return counter.get();\n            }));\n        }\n\n        // CompletableFuture - async composition\n        CompletableFuture<String> future = CompletableFuture\n            .supplyAsync(() -> \"Hello\")\n            .thenApply(s -> s + \" World\")\n            .thenApply(String::toUpperCase)\n            .exceptionally(ex -> \"Error: \" + ex.getMessage());\n\n        System.out.println(future.get()); // HELLO WORLD\n\n        executor.shutdown();\n        executor.awaitTermination(5, TimeUnit.SECONDS);\n    }\n}",
                    "Java's concurrency toolkit provides multiple levels of abstraction: atomic variables for lock-free programming, locks for fine-grained control, and executors for task management.")),
                List.of("What is the difference between synchronized and ReentrantLock?", "Explain the volatile keyword.", "What are virtual threads and how do they differ from platform threads?", "How does CompletableFuture work?", "What is a race condition? How to prevent it?", "Explain the difference between wait/notify and Lock/Condition."),
                List.of("threads", "concurrency", "synchronization", "executor", "locks", "virtual-threads", "completablefuture")),

            createTopic("Exception Handling", "exceptions", "Core Java", "Beginner",
                "Understand checked vs unchecked exceptions, custom exceptions, try-with-resources, and best practices.",
                "## Exception Handling in Java\n\nJava uses a robust exception handling mechanism with try-catch-finally blocks, exception hierarchy, and custom exceptions.\n\n### Exception Hierarchy\n- Throwable\n  - Error (OutOfMemoryError, StackOverflowError) - not recoverable\n  - Exception\n    - Checked (IOException, SQLException) - must handle\n    - Unchecked / RuntimeException (NullPointerException, ArrayIndexOutOfBoundsException)",
                List.of(new CodeExample("Exception Handling Best Practices", "java",
                    "import java.io.*;\n\n// Custom exception hierarchy\nclass AppException extends Exception {\n    private final String errorCode;\n    public AppException(String msg, String code) {\n        super(msg);\n        this.errorCode = code;\n    }\n    public AppException(String msg, String code, Throwable cause) {\n        super(msg, cause);\n        this.errorCode = code;\n    }\n    public String getErrorCode() { return errorCode; }\n}\n\nclass UserNotFoundException extends AppException {\n    public UserNotFoundException(String userId) {\n        super(\"User not found: \" + userId, \"USER_404\");\n    }\n}\n\npublic class ExceptionDemo {\n    // Try-with-resources (Java 7+)\n    static String readFile(String path) throws IOException {\n        try (var reader = new BufferedReader(new FileReader(path))) {\n            return reader.lines()\n                .reduce(\"\", (a, b) -> a + b + \"\\n\");\n        } // Auto-closed!\n    }\n\n    // Multi-catch (Java 7+)\n    static void process(String input) {\n        try {\n            int num = Integer.parseInt(input);\n            int result = 100 / num;\n        } catch (NumberFormatException | ArithmeticException e) {\n            System.err.println(\"Error: \" + e.getMessage());\n        }\n    }\n}",
                    "Custom exception hierarchies with error codes, try-with-resources for automatic cleanup, and multi-catch for concise handling.")),
                List.of("Difference between checked and unchecked exceptions?", "When to use custom exceptions?", "How does try-with-resources work?", "What is exception chaining?", "Best practices for exception handling in production code?"),
                List.of("exceptions", "try-catch", "error-handling", "custom-exception", "checked-unchecked")),

            createTopic("Generics", "generics", "Core Java", "Advanced",
                "Deep dive into Java Generics: type parameters, bounded types, wildcards, type erasure, and generic methods.",
                "## Java Generics\n\nGenerics enable type-safe, reusable code by parameterizing types. Introduced in Java 5, they eliminate the need for explicit casting and catch type errors at compile time.\n\n### Key Concepts\n- Type Parameters (T, E, K, V)\n- Bounded Type Parameters (extends, super)\n- Wildcards (?, extends, super)\n- Type Erasure\n- Generic Methods and Classes",
                List.of(new CodeExample("Generics Deep Dive", "java",
                    "import java.util.*;\n\n// Generic class with bounded type parameter\nclass Repository<T extends Comparable<T>> {\n    private final List<T> items = new ArrayList<>();\n\n    public void add(T item) { items.add(item); }\n\n    public T findMax() {\n        return items.stream().max(Comparable::compareTo).orElse(null);\n    }\n\n    // Generic method\n    public <R> List<R> transform(java.util.function.Function<T, R> fn) {\n        return items.stream().map(fn).toList();\n    }\n}\n\npublic class GenericsDemo {\n    // Wildcards\n    // Upper bounded: reads (producer extends)\n    static double sum(List<? extends Number> list) {\n        return list.stream().mapToDouble(Number::doubleValue).sum();\n    }\n\n    // Lower bounded: writes (consumer super)\n    static void addIntegers(List<? super Integer> list) {\n        list.add(1);\n        list.add(2);\n    }\n\n    public static void main(String[] args) {\n        var repo = new Repository<String>();\n        repo.add(\"Banana\");\n        repo.add(\"Apple\");\n        repo.add(\"Cherry\");\n        System.out.println(\"Max: \" + repo.findMax()); // Cherry\n\n        var lengths = repo.transform(String::length);\n        System.out.println(\"Lengths: \" + lengths);\n\n        // PECS: Producer Extends, Consumer Super\n        System.out.println(sum(List.of(1, 2.5, 3L))); // 6.5\n    }\n}",
                    "The PECS principle (Producer Extends, Consumer Super) is the key to mastering wildcards in generics.")),
                List.of("What is type erasure?", "Explain PECS (Producer Extends, Consumer Super).", "What is the difference between <? extends T> and <? super T>?", "Can you create a generic array in Java? Why not?", "How do bounded type parameters work?"),
                List.of("generics", "type-parameters", "wildcards", "type-erasure", "bounded-types", "pecs")),

            createTopic("JVM Internals", "jvm-internals", "Advanced", "Advanced",
                "Understand how the JVM works: class loading, memory model, garbage collection, JIT compilation, and bytecode.",
                "## JVM Architecture\n\nThe Java Virtual Machine is the cornerstone of Java's platform independence.\n\n### Key Components\n1. **Class Loader** - Loading, Linking, Initialization\n2. **Runtime Data Areas** - Heap, Stack, Method Area, PC Register, Native Method Stack\n3. **Execution Engine** - Interpreter, JIT Compiler, GC",
                List.of(new CodeExample("Memory & GC Monitoring", "java",
                    "public class JVMInternals {\n    public static void main(String[] args) {\n        Runtime runtime = Runtime.getRuntime();\n\n        // Memory info\n        long maxMemory = runtime.maxMemory() / (1024 * 1024);\n        long totalMemory = runtime.totalMemory() / (1024 * 1024);\n        long freeMemory = runtime.freeMemory() / (1024 * 1024);\n\n        System.out.println(\"Max Memory: \" + maxMemory + \" MB\");\n        System.out.println(\"Total Memory: \" + totalMemory + \" MB\");\n        System.out.println(\"Free Memory: \" + freeMemory + \" MB\");\n        System.out.println(\"Used Memory: \" + (totalMemory - freeMemory) + \" MB\");\n        System.out.println(\"Available Processors: \" + runtime.availableProcessors());\n\n        // Allocate memory\n        byte[][] arrays = new byte[100][];\n        for (int i = 0; i < 100; i++) {\n            arrays[i] = new byte[1024 * 1024]; // 1 MB each\n        }\n\n        // Suggest garbage collection\n        System.gc();\n\n        System.out.println(\"\\nAfter allocation:\");\n        System.out.println(\"Used Memory: \" +\n            (runtime.totalMemory() - runtime.freeMemory()) / (1024*1024) + \" MB\");\n    }\n}",
                    "Understanding JVM memory management is crucial for writing performant Java applications and debugging memory-related issues.")),
                List.of("Explain the JVM memory model.", "What is the difference between Stack and Heap?", "How does garbage collection work in Java?", "What is JIT compilation?", "Explain class loading mechanism.", "What are the different types of garbage collectors?"),
                List.of("jvm", "memory", "garbage-collection", "classloader", "bytecode", "jit", "heap", "stack")),

            createTopic("Design Patterns", "design-patterns", "Advanced", "Advanced",
                "Learn the essential Gang of Four design patterns used in Java: Creational, Structural, and Behavioral patterns with practical examples.",
                "## Design Patterns in Java\n\nDesign patterns are proven solutions to recurring software design problems.\n\n### Categories\n1. **Creational** - Object creation (Singleton, Factory, Builder, Prototype)\n2. **Structural** - Object composition (Adapter, Decorator, Proxy, Facade)\n3. **Behavioral** - Object interaction (Observer, Strategy, Command, Iterator)",
                List.of(new CodeExample("Key Design Patterns", "java",
                    "import java.util.*;\n\n// SINGLETON (Thread-safe)\nclass DatabaseConnection {\n    private static volatile DatabaseConnection instance;\n    private DatabaseConnection() {}\n    public static DatabaseConnection getInstance() {\n        if (instance == null) {\n            synchronized (DatabaseConnection.class) {\n                if (instance == null) {\n                    instance = new DatabaseConnection();\n                }\n            }\n        }\n        return instance;\n    }\n}\n\n// BUILDER\nclass User {\n    private final String name;\n    private final String email;\n    private final int age;\n\n    private User(Builder builder) {\n        this.name = builder.name;\n        this.email = builder.email;\n        this.age = builder.age;\n    }\n\n    static class Builder {\n        private String name;\n        private String email;\n        private int age;\n        Builder name(String n) { this.name = n; return this; }\n        Builder email(String e) { this.email = e; return this; }\n        Builder age(int a) { this.age = a; return this; }\n        User build() { return new User(this); }\n    }\n}\n\n// STRATEGY\ninterface SortStrategy {\n    <T extends Comparable<T>> void sort(List<T> list);\n}\nclass BubbleSort implements SortStrategy {\n    @Override\n    public <T extends Comparable<T>> void sort(List<T> list) {\n        System.out.println(\"Bubble sorting...\");\n        Collections.sort(list);\n    }\n}\n\n// OBSERVER\ninterface EventListener {\n    void onEvent(String event);\n}\nclass EventBus {\n    private final List<EventListener> listeners = new ArrayList<>();\n    void subscribe(EventListener l) { listeners.add(l); }\n    void publish(String event) {\n        listeners.forEach(l -> l.onEvent(event));\n    }\n}",
                    "These patterns are frequently asked in interviews and widely used in frameworks like Spring (DI, Proxy), Hibernate (Proxy, Strategy), and more.")),
                List.of("When to use Factory vs Builder pattern?", "What is the Singleton pattern? How to make it thread-safe?", "Explain the Observer pattern with a real-world example.", "What is the Strategy pattern?", "How is the Decorator pattern used in Java I/O?"),
                List.of("design-patterns", "singleton", "factory", "builder", "observer", "strategy", "decorator")),

            createTopic("Java Memory Management", "memory-management", "Advanced", "Advanced",
                "Understand heap, stack, garbage collection algorithms, memory leaks, and performance tuning in Java.",
                "## Memory Management in Java\n\nJava manages memory automatically through garbage collection, but understanding how it works is crucial for writing performant applications.",
                List.of(new CodeExample("Memory Management Demo", "java",
                    "import java.lang.ref.*;\nimport java.util.*;\n\npublic class MemoryDemo {\n    public static void main(String[] args) {\n        // Strong Reference - default\n        Object strong = new Object();\n\n        // Weak Reference - collected when no strong refs exist\n        WeakReference<Object> weak = new WeakReference<>(new Object());\n\n        // Soft Reference - collected only under memory pressure\n        SoftReference<byte[]> cache = new SoftReference<>(new byte[1024 * 1024]);\n\n        // WeakHashMap - entries removed when keys are GC'd\n        Map<Object, String> weakMap = new WeakHashMap<>();\n        Object key = new Object();\n        weakMap.put(key, \"value\");\n\n        key = null; // Key becomes eligible for GC\n        System.gc();\n\n        // After GC, the entry may be removed\n        System.out.println(\"WeakHashMap size: \" + weakMap.size());\n\n        // Memory info\n        Runtime rt = Runtime.getRuntime();\n        System.out.printf(\"Heap: %d MB used / %d MB total%n\",\n            (rt.totalMemory() - rt.freeMemory()) / (1024*1024),\n            rt.totalMemory() / (1024*1024));\n    }\n}",
                    "Understanding reference types (Strong, Weak, Soft, Phantom) is key to managing memory effectively and building caches.")),
                List.of("What are the different types of references in Java?", "How to identify and fix memory leaks?", "What are the different garbage collection algorithms?", "Explain Young Generation vs Old Generation.", "What JVM flags are used for memory tuning?"),
                List.of("memory", "garbage-collection", "heap", "stack", "memory-leak", "reference-types")),

            createTopic("Java I/O and NIO", "io-nio", "Core Java", "Intermediate",
                "Master Java I/O streams, readers/writers, NIO channels, buffers, selectors, and file operations.",
                "## Java I/O and NIO\n\nJava provides two I/O systems: the classic java.io (stream-based) and the modern java.nio (channel/buffer-based).",
                List.of(new CodeExample("I/O and NIO Comparison", "java",
                    "import java.io.*;\nimport java.nio.file.*;\nimport java.nio.charset.StandardCharsets;\nimport java.util.stream.Stream;\n\npublic class IODemo {\n    public static void main(String[] args) throws Exception {\n        Path file = Path.of(\"example.txt\");\n\n        // NIO - Write\n        Files.writeString(file, \"Hello NIO!\\nLine 2\\nLine 3\");\n\n        // NIO - Read all lines\n        var lines = Files.readAllLines(file);\n        lines.forEach(System.out::println);\n\n        // NIO - Stream lines (lazy, memory efficient)\n        try (Stream<String> stream = Files.lines(file)) {\n            long count = stream.filter(l -> l.contains(\"Line\")).count();\n            System.out.println(\"Lines with 'Line': \" + count);\n        }\n\n        // Walk directory tree\n        try (var walker = Files.walk(Path.of(\".\"))) {\n            walker.filter(Files::isRegularFile)\n                  .filter(p -> p.toString().endsWith(\".java\"))\n                  .forEach(System.out::println);\n        }\n\n        // Cleanup\n        Files.deleteIfExists(file);\n    }\n}",
                    "NIO.2 (java.nio.file) is the modern way to handle file operations in Java — cleaner API, better performance, and streaming support.")),
                List.of("Difference between InputStream and Reader?", "What are NIO channels and buffers?", "How does memory-mapped file I/O work?", "What is the difference between blocking and non-blocking I/O?"),
                List.of("io", "nio", "files", "streams", "readers", "writers", "channels", "buffers")),

            createTopic("Annotations & Reflection", "annotations-reflection", "Advanced", "Advanced",
                "Understand how annotations work, create custom annotations, and use the Reflection API for runtime introspection.",
                "## Annotations & Reflection\n\nAnnotations provide metadata about code. Reflection allows runtime inspection and manipulation of classes, methods, and fields.",
                List.of(new CodeExample("Custom Annotations & Reflection", "java",
                    "import java.lang.annotation.*;\nimport java.lang.reflect.*;\n\n// Custom annotation\n@Retention(RetentionPolicy.RUNTIME)\n@Target(ElementType.METHOD)\n@interface Test {\n    String description() default \"\";\n    int priority() default 0;\n}\n\n@Retention(RetentionPolicy.RUNTIME)\n@Target(ElementType.FIELD)\n@interface Inject {\n    String value() default \"\";\n}\n\nclass MyTestClass {\n    @Inject(\"database.url\")\n    private String dbUrl;\n\n    @Test(description = \"Validates user creation\", priority = 1)\n    public void testCreateUser() {\n        System.out.println(\"Testing user creation...\");\n    }\n\n    @Test(description = \"Validates login\", priority = 2)\n    public void testLogin() {\n        System.out.println(\"Testing login...\");\n    }\n}\n\npublic class ReflectionDemo {\n    public static void main(String[] args) throws Exception {\n        Class<?> clazz = MyTestClass.class;\n\n        // Find and run all @Test methods\n        for (Method method : clazz.getDeclaredMethods()) {\n            if (method.isAnnotationPresent(Test.class)) {\n                Test test = method.getAnnotation(Test.class);\n                System.out.println(\"Running: \" + test.description());\n                method.invoke(clazz.getDeclaredConstructor().newInstance());\n            }\n        }\n    }\n}",
                    "This is essentially how testing frameworks like JUnit work — they use reflection to discover and run methods annotated with @Test.")),
                List.of("What are the retention policies for annotations?", "How does Spring use annotations internally?", "What is the performance cost of reflection?", "How to create a custom annotation processor?"),
                List.of("annotations", "reflection", "metadata", "runtime", "custom-annotations")),

            createTopic("Records, Sealed Classes & Pattern Matching", "modern-java", "Java 14+", "Intermediate",
                "Master the modern Java language features: Records for data classes, Sealed classes for controlled hierarchies, and Pattern Matching for elegant type checks.",
                "## Modern Java Language Features\n\nJava 14-21 introduced three interconnected features that modernize how we write Java code.",
                List.of(new CodeExample("Modern Java in Action", "java",
                    "// Records - immutable data carriers\nrecord Point(double x, double y) {\n    double distanceTo(Point other) {\n        return Math.sqrt(Math.pow(x - other.x, 2) + Math.pow(y - other.y, 2));\n    }\n}\n\n// Sealed interface + Records = Algebraic Data Types\nsealed interface Shape permits Circle, Rect, Triangle {}\nrecord Circle(Point center, double radius) implements Shape {}\nrecord Rect(Point topLeft, double w, double h) implements Shape {}\nrecord Triangle(Point a, Point b, Point c) implements Shape {}\n\npublic class ModernJava {\n    // Pattern matching with switch\n    static double area(Shape shape) {\n        return switch (shape) {\n            case Circle(var center, var r) -> Math.PI * r * r;\n            case Rect(var tl, var w, var h) -> w * h;\n            case Triangle(var a, var b, var c) -> {\n                // Heron's formula\n                double ab = a.distanceTo(b);\n                double bc = b.distanceTo(c);\n                double ca = c.distanceTo(a);\n                double s = (ab + bc + ca) / 2;\n                yield Math.sqrt(s * (s-ab) * (s-bc) * (s-ca));\n            }\n        }; // Exhaustive - no default needed!\n    }\n\n    // Guarded patterns\n    static String classify(Shape shape) {\n        return switch (shape) {\n            case Circle c when area(c) > 100 -> \"Large circle\";\n            case Circle c -> \"Small circle\";\n            case Rect r when r.w() == r.h() -> \"Square\";\n            case Rect r -> \"Rectangle\";\n            case Triangle t -> \"Triangle\";\n        };\n    }\n\n    public static void main(String[] args) {\n        var shapes = java.util.List.of(\n            new Circle(new Point(0, 0), 5),\n            new Rect(new Point(0, 0), 4, 6),\n            new Triangle(new Point(0,0), new Point(3,0), new Point(0,4))\n        );\n        shapes.forEach(s -> System.out.printf(\"%s: area=%.2f -> %s%n\",\n            s, area(s), classify(s)));\n    }\n}",
                    "Records + Sealed classes + Pattern Matching together form Java's version of algebraic data types — enabling exhaustive, type-safe, and concise code.")),
                List.of("What is the difference between Records and regular classes?", "When should you use sealed classes?", "Can records extend other classes?", "How does exhaustive pattern matching work?"),
                List.of("records", "sealed-classes", "pattern-matching", "modern-java", "algebraic-types"))
        );
        topicRepo.saveAll(topics);
    }

    private Topic createTopic(String title, String slug, String category, String difficulty,
                               String description, String content, List<CodeExample> examples,
                               List<String> interviewQs, List<String> tags) {
        Topic t = new Topic();
        t.setTitle(title);
        t.setSlug(slug);
        t.setCategory(category);
        t.setDifficulty(difficulty);
        t.setDescription(description);
        t.setContent(content);
        t.setCodeExamples(examples);
        t.setInterviewQuestions(interviewQs);
        t.setTags(tags);
        return t;
    }

